```python
def isBipartite(graph):
    n = len(graph)
    visited = [[-1] * 2 for _ in range(n)]

    for node in range(n):
        if visited[node][0] == -1:
            stack = [(node, 0)]
            while stack:
                u, color = stack.pop()
                if visited[u][color] != color:
                    return False
                for neighbor in graph[u]:
                    if visited[neighbor][color ^ 1] == -1:
                        stack.append((neighbor, color ^ 1))
                        visited[neighbor][color ^ 1] = color

    return True
```

