            next_point = (current[0] + dx, current[1] + dy)
            if -104 <= next_point[0] <= 104 and -104 <= next_point[1] <= 104:
                if next_point not in visited:
                    heapq.heappush(queue, (manhattan_distance(next_point, target), next_point))
    return False

def escape(ghosts, target):
    graph = {(0, 0): {}}
    for ghost in ghosts:
        graph[ghost] = set()
    for ghost in graph:
        for dx, dy in [(0, 1), (0, -1), (1, 0), (-1, 0)]:
